UPDATE product_mapping pm
SET selling_price = pp.gia_ban
FROM pos_prices pp
WHERE pm.ex_code = pp.ex_code;

-- Kiểm tra kết quả
SELECT
  COUNT(*) FILTER (WHERE selling_price IS NOT NULL AND selling_price > 0) AS co_gia,
  COUNT(*) FILTER (WHERE selling_price IS NULL OR selling_price = 0)      AS chua_co_gia,
  COUNT(*)                                                                  AS tong
FROM product_mapping;


select p.code, p.name , pm.selling_price
from product_mapping pm inner join item p on pm.item_id = p.id
where pm.selling_price is null

select * from product_mapping

-- Update item_group_id dựa vào prefix của item.code
-- Prefix = phần trước dấu '-' đầu tiên (VD: 'PL-BANH-BIA' → 'PL')
-- Chỉ update những item chưa có item_group_id

UPDATE item i
SET item_group_id = g.id
FROM item_group g
WHERE i.item_group_id IS NULL
  AND split_part(i.code, '-', 1) = g.code;


select * from item where item_type = 'PRODUCT'

-- Kiểm tra kết quả
SELECT
    split_part(i.code, '-', 1) AS prefix,
    g.code                     AS group_code,
    g.name                     AS group_name,
    COUNT(*)                   AS so_item
FROM item i
JOIN item_group g ON i.item_group_id = g.id
GROUP BY split_part(i.code, '-', 1), g.code, g.name
ORDER BY g.code;

-- Báo các item vẫn chưa có group (prefix không khớp)
SELECT code, name, item_type
FROM item
WHERE item_group_id IS NULL
ORDER BY item_type, code;
